#include <iostream>
#include <vector>
#include <thread>
#include <chrono>

class Enemy {
private:
    int* healthPtr;  // Simulates a large allocation

public:
    Enemy(int health) {
        healthPtr = new int(health);
        std::cout << "Enemy spawned (HP: " << *healthPtr << ")" << std::endl;
    }

    ~Enemy() {
        delete healthPtr;
        std::cout << "Enemy destroyed" << std::endl;
    }
};

void spawnEnemyLeak(int health) {
    Enemy* enemy = new Enemy(health);
    // Forgot to delete! LEAK!
}

void spawnEnemySafe(int health) {
    Enemy* enemy = new Enemy(health);
    delete enemy;  // Safe
}

int main() {
    std::cout << "=== Memory Leaks ===" << std::endl;

    std::cout << "\n--- Leaking memory ---" << std::endl;
    for (int i = 0; i < 3; i++) {
        spawnEnemyLeak(100 + i * 10);
        std::cout << "Leak created (" << i + 1 << "/3)" << std::endl;
    }

    std::cout << "\n--- Not leaking memory ---" << std::endl;
    for (int i = 0; i < 3; i++) {
        spawnEnemySafe(100 + i * 10);
        std::cout << "Safe allocation (" << i + 1 << "/3)" << std::endl;
    }

    std::cout << "\n--- The problem with memory leaks ---" << std::endl;
    std::cout << "Memory leaks cause:" << std::endl;
    std::cout << "  • Slower performance over time" << std::endl;
    std::cout << "  • Crashes after running for hours" << std::endl;
    std::cout << "  • Unpredictable behavior" << std::endl;
    std::cout << "  • Wasted system resources" << std::endl;
    std::cout << "\nIn games:" << std::endl;
    std::cout << "  • FPS drops" << std::endl;
    std::cout << "  • Longer loading times" << std::endl;
    std::cout << "  • Crashes during boss fights" << std::endl;

    std::cout << "\n--- How to find leaks ---" << std::endl;
    std::cout << "1. Use valgrind: valgrind --leak-check=full ./program" << std::endl;
    std::cout << "2. Use AddressSanitizer: g++ -fsanitize=address program.cpp" << std::endl;
    std::cout << "3. Use smart pointers (next lesson!)" << std::endl;

    return 0;
}

phase2.brokenCode:
#include <iostream>

class Player {
private:
    int* health;

public:
    Player(int h) : health(new int(h)) {}

    // Forgot destructor! LEAK!
    // ~Player() { delete health; }
};

int main() {
    for (int i = 0; i < 1000; i++) {
        Player* p = new Player(100);
        // Forgot to delete p!
        // delete p;
    }

    std::cout << "1000 players allocated (and leaked!)" << std::endl;
    return 0;
}

phase2.explanation:
Two leaks in one!

1. `Player` doesn't have a destructor → `health` is leaked when `Player` is destroyed
2. `Player* p` is never deleted → the `Player` object itself is leaked

**The fix:**
```cpp
class Player {
    int* health;
public:
    Player(int h) : health(new int(h)) {}
    ~Player() { delete health; }  // ← Destructor!
};

// And in main:
delete p;  // ← Delete the player!
```

**PlusPlus-chan says:**
"Every allocation is a responsibility. Track your `new`s. Match them with `delete`s."

phase3.solution:
#include <iostream>

void leakMemory() {
    int* ptr = new int(42);
    std::cout << "Memory allocated (LEAK!)" << std::endl;
    // No delete — intentional leak
}

void safeMemory() {
    int* ptr = new int(42);
    std::cout << "Memory allocated and freed" << std::endl;
    delete ptr;
}

int main() {
    std::cout << "=== Leaking memory ===" << std::endl;
    for (int i = 0; i < 3; i++) {
        leakMemory();
    }

    std::cout << "\n=== Safe memory ===" << std::endl;
    for (int i = 0; i < 3; i++) {
        safeMemory();
    }

    std::cout << "\n⚠️ Memory leaks happen when you forget delete!" << std::endl;

    return 0;
}
